import os
import sys
import json
import time
import socket
import hashlib
from collections import defaultdict

class AttackGraph:
    """Directed graph of compromised hosts, credentials, and access paths.
    Nodes = hosts (IP + hostname + OS + role + compromise level).
    Edges = access methods (SSH key, PtH, PtT, RDP, WMI, DCOM, PsExec, etc.).
    Supports shortest-path-to-objective, pivot planning, and recursive expansion.
    """
    def __init__(self):
        self.nodes = {}  # ip -> {hostname, os, role, compromised, creds, services, timestamp}
        self.edges = []  # [{src, dst, method, credential, weight, success, timestamp}]
        self.credentials = []  # [{username, secret, type, source_host, tested_on}]
        self.objectives = []  # [{type, target, description, achieved}]

    def add_node(self, ip, **kwargs):
        if ip not in self.nodes:
            self.nodes[ip] = {'ip': ip, 'hostname': None, 'os': None, 'role': None,
                              'compromised': False, 'compromise_level': 'none',
                              'services': [], 'creds_found': [], 'timestamp': time.time()}
        self.nodes[ip].update(kwargs)
        return self.nodes[ip]

    def add_edge(self, src, dst, method, credential=None, weight=1, success=False):
        edge = {'src': src, 'dst': dst, 'method': method, 'credential': credential,
                'weight': weight, 'success': success, 'timestamp': time.time()}
        self.edges.append(edge)
        return edge

    def add_credential(self, username, secret, cred_type='password', source_host=None):
        cred = {'username': username, 'secret': secret, 'type': cred_type,
                'source_host': source_host, 'tested_on': [], 'valid_on': []}
        self.credentials.append(cred)
        return cred

    def add_objective(self, obj_type, target, description=''):
        obj = {'type': obj_type, 'target': target, 'description': description, 'achieved': False}
        self.objectives.append(obj)
        return obj

    def get_compromised(self):
        return [ip for ip, node in self.nodes.items() if node['compromised']]

    def get_reachable_from(self, ip):
        """Get all nodes directly reachable from a compromised node."""
        reachable = set()
        for edge in self.edges:
            if edge['src'] == ip and edge['success']:
                reachable.add(edge['dst'])
        return reachable

    def shortest_path(self, src, dst):
        """BFS shortest path through successful edges."""
        if src == dst:
            return [src]
        adj = defaultdict(list)
        for edge in self.edges:
            if edge['success']:
                adj[edge['src']].append((edge['dst'], edge))
        visited = {src}
        queue = [(src, [src], [])]
        while queue:
            current, path, edge_path = queue.pop(0)
            for neighbor, edge in adj[current]:
                if neighbor not in visited:
                    new_path = path + [neighbor]
                    new_edges = edge_path + [edge]
                    if neighbor == dst:
                        return {'path': new_path, 'edges': new_edges, 'hops': len(new_edges)}
                    visited.add(neighbor)
                    queue.append((neighbor, new_path, new_edges))
        return None

    def path_to_objective(self, src=None):
        """Find shortest path from any compromised node to any objective."""
        sources = [src] if src else self.get_compromised()
        best = None
        for s in sources:
            for obj in self.objectives:
                if not obj['achieved']:
                    result = self.shortest_path(s, obj['target'])
                    if result and (best is None or result['hops'] < best['hops']):
                        best = result
                        best['objective'] = obj
        return best

    def suggest_next_targets(self, max_targets=5):
        """Suggest best targets for lateral movement based on graph analysis."""
        compromised = set(self.get_compromised())
        candidates = []
        for ip, node in self.nodes.items():
            if ip in compromised:
                continue
            score = 0
            reasons = []
            # Higher score for nodes with more services
            score += len(node.get('services', [])) * 2
            # Higher score for nodes adjacent to objectives
            for obj in self.objectives:
                if ip == obj['target']:
                    score += 100
                    reasons.append('IS_OBJECTIVE')
            # Higher score for domain controllers
            if node.get('role') in ('domain_controller', 'dc', 'pdc'):
                score += 50
                reasons.append('DOMAIN_CONTROLLER')
            # Higher score for servers vs workstations
            if 'server' in (node.get('os', '') or '').lower():
                score += 10
                reasons.append('SERVER_OS')
            # Check if we have untested credentials for this host
            for cred in self.credentials:
                if ip not in cred['tested_on']:
                    score += 5
                    reasons.append(f'UNTESTED_CRED({cred["username"]})')
            # Penalize already-failed attempts
            failed_attempts = sum(1 for e in self.edges if e['dst'] == ip and not e['success'])
            score -= failed_attempts * 3
            if score > 0:
                candidates.append({'ip': ip, 'score': score, 'reasons': reasons[:5],
                                    'node': node, 'failed_attempts': failed_attempts})
        candidates.sort(key=lambda x: x['score'], reverse=True)
        return candidates[:max_targets]

    def expand_from_host(self, ip):
        """Plan expansion: which credentials to try on which services from this host."""
        plan = []
        for target_ip, node in self.nodes.items():
            if target_ip == ip or node['compromised']:
                continue
            for service in node.get('services', []):
                for cred in self.credentials:
                    if target_ip not in cred['tested_on']:
                        method = self._match_method(service, cred)
                        if method:
                            plan.append({
                                'src': ip, 'dst': target_ip, 'method': method,
                                'service': service, 'credential': cred['username'],
                                'cred_type': cred['type'],
                            })
        return plan

    def _match_method(self, service, cred):
        """Match service to lateral movement method."""
        svc = service.get('service', '').lower() if isinstance(service, dict) else str(service).lower()
        port = service.get('port', 0) if isinstance(service, dict) else 0
        ctype = cred.get('type', 'password')
        if 'ssh' in svc or port == 22:
            if ctype in ('password', 'ssh_key'):
                return 'ssh'
        elif 'smb' in svc or port == 445:
            if ctype == 'ntlm_hash':
                return 'pass_the_hash'
            elif ctype == 'password':
                return 'psexec'
        elif 'rdp' in svc or port == 3389:
            return 'rdp'
        elif 'winrm' in svc or port == 5985:
            if ctype == 'ntlm_hash':
                return 'pass_the_hash_winrm'
            return 'winrm'
        elif 'wmi' in svc or port == 135:
            return 'wmi_exec'
        elif 'mysql' in svc or port == 3306:
            return 'mysql'
        elif 'postgres' in svc or port == 5432:
            return 'postgresql'
        elif 'mssql' in svc or port == 1433:
            return 'mssql'
        elif 'ldap' in svc or port == 389:
            return 'ldap'
        return None

    def to_dict(self):
        return {'nodes': self.nodes, 'edges': self.edges,
                'credentials': [dict(c, secret=c['secret'][:3]+'***') for c in self.credentials],
                'objectives': self.objectives,
                'stats': {'total_nodes': len(self.nodes),
                          'compromised': len(self.get_compromised()),
                          'total_edges': len(self.edges),
                          'successful_edges': sum(1 for e in self.edges if e['success']),
                          'credentials': len(self.credentials),
                          'objectives_achieved': sum(1 for o in self.objectives if o['achieved'])}}

# Example usage and demo
def demo_attack_graph():
    g = AttackGraph()
    # Initial foothold
    g.add_node('10.0.0.50', hostname='web01', os='Ubuntu 22.04', role='webserver', compromised=True, compromise_level='root')
    # Discovered network
    g.add_node('10.0.0.1', hostname='dc01', os='Windows Server 2019', role='domain_controller', services=[{'service': 'SMB', 'port': 445}, {'service': 'LDAP', 'port': 389}, {'service': 'WinRM', 'port': 5985}])
    g.add_node('10.0.0.10', hostname='db01', os='Ubuntu 22.04', role='database', services=[{'service': 'SSH', 'port': 22}, {'service': 'PostgreSQL', 'port': 5432}])
    g.add_node('10.0.0.20', hostname='app01', os='Windows Server 2019', role='application', services=[{'service': 'SMB', 'port': 445}, {'service': 'RDP', 'port': 3389}])
    # Objective
    g.add_objective('domain_admin', '10.0.0.1', 'Achieve Domain Admin on DC01')
    # Found credentials
    g.add_credential('admin', 'P@ssw0rd123', 'password', '10.0.0.50')
    g.add_credential('svc_sql', 'aad3b435b51404eeaad3b435b51404ee:31d6cfe0d16ae931b73c59d7e0c089c0', 'ntlm_hash', '10.0.0.50')
    # Plan expansion
    targets = g.suggest_next_targets()
    plan = g.expand_from_host('10.0.0.50')
    return {'graph': g.to_dict(), 'next_targets': targets, 'expansion_plan': plan}

if __name__ == '__main__':
    out = demo_attack_graph()
    print(json.dumps(out, indent=2, default=str))

